import React, { useState, useEffect, useRef } from 'react';
import { useMusic } from '../context/MusicContext';
import { Play, Pause, SkipBack, SkipForward, ListPlus, Music, Heart } from 'lucide-react';
import axios from 'axios';

const GlobalPlayer = () => {
  const { currentSong, isPlaying, togglePlay, handleNext, handlePrev, favorites, toggleLike, currentTime, duration, seekTo } = useMusic();
  const [showMenu, setShowMenu] = useState(false);
  const [userPlaylists, setUserPlaylists] = useState([]);
  const menuRef = useRef(null);
  const user = JSON.parse(localStorage.getItem('user'));

  // Đồng bộ trạng thái Like
  const isLiked = currentSong && favorites.includes(String(currentSong._id));

  // Tính % tiến trình cho thanh slider
  const progress = (currentTime / duration) * 100 || 0;

  useEffect(() => {
    const handleClickOutside = (e) => { if (menuRef.current && !menuRef.current.contains(e.target)) setShowMenu(false); };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const fetchPlaylists = async () => {
    if (!user) return alert("Vui lòng đăng nhập!");
    try {
      const res = await axios.get(`http://localhost:5000/api/playlists/user/${user._id || user.id}`);
      setUserPlaylists(res.data);
      setShowMenu(!showMenu);
    } catch (err) { console.error(err); }
  };

  const formatTime = (time) => {
    const mins = Math.floor(time / 60) || 0;
    const secs = Math.floor(time % 60) || 0;
    return `${mins}:${secs < 10 ? '0' : ''}${secs}`;
  };

  if (!currentSong) return null;

  return (
    <div style={playerContainer}>
      <div style={infoSection}>
        <img src={`http://localhost:5000${currentSong.imageUrl}`} style={playerImg} alt="" />
        <div style={{ overflow: 'hidden', flex: 1 }}>
          {/* Sửa lỗi hiển thị tiêu đề bài hát */}
          <div style={songTitle}>{currentSong.title || currentSong.name}</div>
          <div style={songArtist}>{currentSong.artist || currentSong.singer}</div>
        </div>
        <button onClick={() => toggleLike(currentSong._id)} style={btnTransparent}>
          <Heart size={20} fill={isLiked ? "#1db954" : "none"} color={isLiked ? "#1db954" : "#b3b3b3"} />
        </button>
      </div>

      <div style={controlsSection}>
        <div style={buttonGroup}>
          <SkipBack size={22} style={iconBtn} onClick={handlePrev} />
          <button onClick={togglePlay} style={mainPlayBtn}>
            {isPlaying ? <Pause size={24} fill="black" /> : <Play size={24} fill="black" style={{marginLeft:4}} />}
          </button>
          <SkipForward size={22} style={iconBtn} onClick={handleNext} />
        </div>
        <div style={progressBarContainer}>
          <span style={timeText}>{formatTime(currentTime)}</span>
          <input type="range" min="0" max="100" value={progress} onChange={(e) => seekTo(e.target.value)} style={sliderStyle} />
          <span style={timeText}>{formatTime(duration)}</span>
        </div>
      </div>

      <div style={extraSection} ref={menuRef}>
        <button onClick={fetchPlaylists} style={addPlaylistBtn}><ListPlus size={18} /> <span>Playlist</span></button>
        {showMenu && (
          <div style={dropdownMenu}>
            {userPlaylists.map(pl => (
              <div key={pl._id} style={menuItem} onClick={async () => {
                await axios.put(`http://localhost:5000/api/playlists/${pl._id}/add`, { songId: currentSong._id });
                setShowMenu(false);
              }}><Music size={14} /> {pl.title}</div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

const playerContainer = { position: 'fixed', bottom: 0, left: 0, right: 0, background: '#181818', color: '#fff', padding: '15px 40px', display: 'flex', alignItems: 'center', zIndex: 10000, borderTop: '1px solid #282828' };
const infoSection = { width: '30%', display: 'flex', alignItems: 'center', gap: '12px' };
const playerImg = { width: '56px', height: '56px', borderRadius: '4px', objectFit: 'cover' };
const songTitle = { fontWeight: '600', fontSize: '14px', whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' };
const songArtist = { fontSize: '12px', color: '#b3b3b3' };
const controlsSection = { flex: 1, display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '8px' };
const buttonGroup = { display: 'flex', alignItems: 'center', gap: '25px' };
const iconBtn = { cursor: 'pointer', color: '#b3b3b3' };
const mainPlayBtn = { background: '#fff', color: '#000', border: 'none', width: '40px', height: '40px', borderRadius: '50%', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center' };
const progressBarContainer = { display: 'flex', alignItems: 'center', width: '100%', maxWidth: '500px', gap: '10px' };
const sliderStyle = { flex: 1, accentColor: '#1db954', cursor: 'pointer', height: '4px' };
const timeText = { fontSize: '11px', color: '#a7a7a7', minWidth: '35px' };
const extraSection = { width: '30%', display: 'flex', justifyContent: 'flex-end', position: 'relative' };
const addPlaylistBtn = { background: 'transparent', color: '#b3b3b3', border: '1px solid #404040', padding: '8px 15px', borderRadius: '20px', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '8px' };
const dropdownMenu = { position: 'absolute', bottom: '60px', right: 0, width: '200px', background: '#282828', borderRadius: '8px', padding: '5px 0', zIndex: 100 };
const menuItem = { padding: '10px 15px', cursor: 'pointer', fontSize: '13px', display: 'flex', alignItems: 'center', gap: '10px' };
const btnTransparent = { background: 'none', border: 'none', cursor: 'pointer' };

export default GlobalPlayer;
